exercises.solution_code:
#include <iostream>
#include <iomanip>

struct Point
{
    double x;
    double y;
};

double squaredDistance(const Point& p)
{
    return p.x * p.x + p.y * p.y;
}

int main()
{
    double x1{}, y1{}, x2{}, y2{};
    std::cin >> x1 >> y1 >> x2 >> y2;

    Point p1 { x1, y1 };
    Point p2 { x2, y2 };

    std::cout << std::fixed << std::setprecision(1);
    std::cout << "P1: (" << p1.x << ", " << p1.y << ")\n";
    std::cout << "P2: (" << p2.x << ", " << p2.y << ")\n";

    if (squaredDistance(p1) >= squaredDistance(p2))
        std::cout << "Farther from origin: P1\n";
    else
        std::cout << "Farther from origin: P2\n";

    return 0;
}

