    int code{};
    std::cin >> code;

    Role role{ static_cast<Role>(code) };

    std::cout << "Can view: "   << (canView(role)   ? "yes" : "no") << '\n';
    std::cout << "Can edit: "   << (canEdit(role)   ? "yes" : "no") << '\n';
    std::cout << "Can delete: " << (canDelete(role) ? "yes" : "no") << '\n';

    return 0;
}

