#include <iostream>
#include <string>
#include <string_view>

enum class Rarity
{
    Common    = 0,
    Rare      = 1,
    Legendary = 2
};

struct Item
{
    std::string name;
    int         quantity;
    Rarity      rarity;
};

std::string_view rarityLabel(Rarity r)
{
    switch (r)
    {
        case Rarity::Common:    return "Common";
        case Rarity::Rare:      return "Rare";
        case Rarity::Legendary: return "Legendary";
        default:                return "Unknown";
    }
}

void printItem(const Item& item)
{
    std::cout << item.name << " x" << item.quantity
              << " [" << rarityLabel(item.rarity) << "]\n";
}

int main()
{
    std::string n1, n2, n3;
    int q1{}, q2{}, q3{};
    int c1{}, c2{}, c3{};

    std::cin >> n1 >> q1 >> c1;
    std::cin >> n2 >> q2 >> c2;
    std::cin >> n3 >> q3 >> c3;

    Item item1{ n1, q1, static_cast<Rarity>(c1) };
    Item item2{ n2, q2, static_cast<Rarity>(c2) };
    Item item3{ n3, q3, static_cast<Rarity>(c3) };

    printItem(item1);
    printItem(item2);
    printItem(item3);

    int total{ item1.quantity + item2.quantity + item3.quantity };

    std::cout << '\n';
    std::cout << "Total items: " << total << '\n';

    return 0;
}

